/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWOrdemProducao-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&ProNom.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Descrição") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ProNom) EndIf
If not (&ProRef.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cód.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ProRef) EndIf
If not (&ProSetCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Setor") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &ProSetCod EndIf
If not (&ProClsPrdCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Clasf.Produção") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &ProClsPrdCod EndIf
If not (&GrupHie.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Grupo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&GrupHie) EndIf
If not (&AuxGrupHie.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Hierarquia") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AuxGrupHie) EndIf
If not (&ProTipDef.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Definição") If Not &ProTipDef.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &ProTipDef.EnumerationDescription() Endif EndIf
If not (&FilCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Filial") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilCod EndIf
If not (&ProGraCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Grade") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &ProGraCod EndIf
If not (&ProSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Produto Ativo") If Not &ProSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &ProSts.EnumerationDescription() Endif EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&VisibleColumnCount = 0 If &Session.Get(!'WWOrdemProducaoColumnsSelector') <> '' &ColumnsSelectorXML = &Session.Get(!'WWOrdemProducaoColumnsSelector') &ColumnsSelector.FromXml(&ColumnsSelectorXML) Else Do 'InitializeColumnsSelector' EndIf
&ColumnsSelector.Columns.Item(5).IsVisible = False &ColumnsSelector.Columns.Item(6).IsVisible = False &ColumnsSelector.Columns.Item(17).IsVisible = False &ColumnsSelector.Columns.Item(18).IsVisible = False &ColumnsSelector.Columns.Item(21).IsVisible = False For &ColumnsSelector_Column in &ColumnsSelector.Columns If &ColumnsSelector_Column.IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = GetMessageText(iif(&ColumnsSelector_Column.DisplayName.IsEmpty(), &ColumnsSelector_Column.ColumnName, &ColumnsSelector_Column.DisplayName)) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Color = 11 &VisibleColumnCount += 1 EndIf EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod ProSts ProGraCod ProSetCod ProCod when &OrderedBy = 1 order EmpCod FilCod ProSts ProGraCod ProSetCod ProNom when &OrderedBy = 2 order EmpCod FilCod ProSts ProGraCod ProSetCod (EstPrio) when &OrderedBy = 3 order EmpCod FilCod ProSts ProGraCod ProSetCod EstPrd when &OrderedBy = 4 order EmpCod FilCod ProSts ProGraCod ProSetCod (EstPrd) when &OrderedBy = 5 order EmpCod FilCod ProSts ProGraCod ProSetCod EstQtd when &OrderedBy = 6 order EmpCod FilCod ProSts ProGraCod ProSetCod EstDias when &OrderedBy = 7 order EmpCod FilCod ProSts ProGraCod ProSetCod (EstSug) when &OrderedBy = 8 order EmpCod FilCod ProSts ProGraCod ProSetCod (EstMinVen) when &OrderedBy = 9 order EstABC_Ren when &OrderedBy = 10 AND &OrderedDsc = False order (EstABC_Ren) when &OrderedBy = 10 AND &OrderedDsc = True order EstABC_Qtd when &OrderedBy = 11 AND &OrderedDsc = False order (EstABC_Qtd) when &OrderedBy = 11 AND &OrderedDsc = True order EstPrio when &OrderedBy = 12 AND &OrderedDsc = False order (EstPrio) when &OrderedBy = 12 AND &OrderedDsc = True
using DSWWOrdemProducao(&ProNom, &ProRef, &ProSetCod, &ProClsPrdCod, &GrupHie, &AuxGrupHie , &ProTipDef, &FilCod, &ProGraCod, &ProSts)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &VisibleColumnCount = 0 If &ColumnsSelector.Columns.Item(1).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(ProRef) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(2).IsVisible = True &gridProNom = ProNom &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(&gridProNom) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(3).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(EstABC_Ren) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(4).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(EstABC_Qtd) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(7).IsVisible = True &gridEstPrd_Formatado = EstPrd_Formatado &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstPrd_Formatado &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(8).IsVisible = True &gridEstCom_Formatado = EstCom_Formatado &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstCom_Formatado &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(9).IsVisible = True &gridEstQtd_Formatado = EstQtd_Formatado &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstQtd_Formatado &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(10).IsVisible = True &gridEstVen_Formatado = EstVen_Formatado &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstVen_Formatado &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(11).IsVisible = True &gridEstSdo_Formatado = EstSdo_Formatado &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstSdo_Formatado &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(12).IsVisible = True &gridEstMinDia = EstMinDia &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstMinDia &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(13).IsVisible = True &gridEstMinVen = EstMinVen &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstMinVen &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(14).IsVisible = True &gridEstMin_Formatado = EstMin_Formatado &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstMin_Formatado &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(15).IsVisible = True &gridEstFabMin_Formatado = EstFabMin_Formatado &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstFabMin_Formatado &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(16).IsVisible = True &gridEstSug_Formatado = EstSug_Formatado &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = &gridEstSug_Formatado &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(19).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = EstPrio &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(20).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = ProSetCod &VisibleColumnCount += 1 EndIf
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'InitializeColumnsSelector'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ColumnsSelector = new WWPColumnsSelector() WWP_ColumnsSelector_Add(&ColumnsSelector, !"ProRef", '', !'Ref.Cód.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridProNom", '', !'Produto Descrição', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"EstABC_Ren", '', !'ABC.R', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"EstABC_Qtd", '', !'ABC.Q', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&UltEstQtd", '', !'Ult.Qtd', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&EstUltOrd", '', !'Ult.Ord.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstPrd_Formatado", '', !'Produção', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstCom_Formatado", '', !'Compras', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstQtd_Formatado", '', !'Estoque', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstVen_Formatado", '', !'Vendas', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstSdo_Formatado", '', !'Saldo', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstMinDia", '', !'D.I.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstMinVen", '', !'Vendido', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstMin_Formatado", '', !'Mínimo', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstFabMin_Formatado", '', !'Fab.Mín.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridEstSug_Formatado", '', !'Sugestão', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&EstFab", '', !'Fabricar', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&EstDias", '', !'D.E.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"EstPrio", '', !'Prioridade', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"ProSetCod", '', !'Setor', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&SalvaLinha", '', !'', True, '')
&UserCustomValue = LoadColumnsSelectorState.Udp(!'WWOrdemProducaoColumnsSelector') If not(&UserCustomValue.IsEmpty()) &ColumnsSelectorAux.FromXml(&UserCustomValue) WWP_ColumnSelector_UpdateColumns(&ColumnsSelectorAux, &ColumnsSelector) EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWOrdemProducaoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWOrdemProducaoGridState")) Else &GridState.FromXml(&Session.Get(!"WWOrdemProducaoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PRONOM" &ProNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROREF" &ProRef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSETCOD" &ProSetCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROCLSPRDCOD" &ProClsPrdCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"GRUPHIE" &GrupHie.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"AUXGRUPHIE" &AuxGrupHie.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROTIPDEF" &ProTipDef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROGRACOD" &ProGraCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSTS" &ProSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
